import{c as t,Q as i,j as o,m as a}from"./chunks/framework.rlpw0eGz.js";const p=JSON.parse('{"title":"🌡️ Hardware Monitoring & Diagnostics Guide","description":"","frontmatter":{},"headers":[],"relativePath":"HARDWARE.md","filePath":"HARDWARE.md"}'),r={name:"HARDWARE.md"};function s(n,e,l,d,c,h){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="🌡️-hardware-monitoring-diagnostics-guide" tabindex="-1">🌡️ Hardware Monitoring &amp; Diagnostics Guide <a class="header-anchor" href="#🌡️-hardware-monitoring-diagnostics-guide" aria-label="Permalink to &quot;🌡️ Hardware Monitoring &amp; Diagnostics Guide&quot;">​</a></h1><p>The <code>Hardware/</code> directory contains portable, industry-standard diagnostic tools designed to monitor hardware specifications, track temperatures, and verify that system optimizations are active and stable.</p><hr><h2 id="🛠️-integrated-diagnostic-tools" tabindex="-1">🛠️ Integrated Diagnostic Tools <a class="header-anchor" href="#🛠️-integrated-diagnostic-tools" aria-label="Permalink to &quot;🛠️ Integrated Diagnostic Tools&quot;">​</a></h2><h3 id="_1-cpu-z" tabindex="-1">1. CPU-Z <a class="header-anchor" href="#_1-cpu-z" aria-label="Permalink to &quot;1. CPU-Z&quot;">​</a></h3><ul><li><strong>File</strong>: <code>CPU-Z.exe</code></li><li><strong>Purpose</strong>: Gathers in-depth data regarding your processor, motherboard, chipset, and memory channels.</li><li><strong>Key Parameters to Monitor</strong>: <ul><li><strong>Core Speed / Multiplier</strong>: Verify that your CPU is scaling to its advertised boost clocks and that custom performance power plans are actively preventing aggressive core parking.</li><li><strong>Memory Tab</strong>: Confirm that your RAM is running in Dual Channel mode and that the motherboard&#39;s XMP (Extreme Memory Profile) is active (by checking DRAM Frequency and comparing against advertised timings).</li></ul></li></ul><h3 id="_2-gpu-z" tabindex="-1">2. GPU-Z <a class="header-anchor" href="#_2-gpu-z" aria-label="Permalink to &quot;2. GPU-Z&quot;">​</a></h3><ul><li><strong>File</strong>: <code>GPU-Z.exe</code></li><li><strong>Purpose</strong>: A lightweight diagnostic utility tailored specifically to GPU sensors, BIOS revisions, and graphic driver specifications.</li><li><strong>Key Parameters to Monitor</strong>: <ul><li><strong>Sensors Tab (Real-Time)</strong>: Track GPU Core Clock, Memory Clock, and Fan Speeds during active benchmarking.</li><li><strong>GPU Temperature vs. Hot Spot Temperature</strong>: Ensure the delta between core and hotspot temperatures does not exceed 15-20°C (higher deltas indicate worn thermal paste or uneven cooler pressure).</li><li><strong>PCIe Slot Speed</strong>: Verify that the GPU is running at its maximum bus width (e.g., <code>PCIe x16 4.0 @ x16 4.0</code> under load) and not downscaling during gaming.</li></ul></li></ul><h3 id="_3-hwmonitor" tabindex="-1">3. HWMonitor <a class="header-anchor" href="#_3-hwmonitor" aria-label="Permalink to &quot;3. HWMonitor&quot;">​</a></h3><ul><li><strong>File</strong>: <code>HW-Monitor.exe</code></li><li><strong>Purpose</strong>: A comprehensive hardware health monitoring program that tracks motherboard voltages, system fan speeds, disk SSD temperatures, and core CPU/GPU sensors simultaneously.</li><li><strong>Key Parameters to Monitor</strong>: <ul><li><strong>Temperatures (CPU Cores)</strong>: Confirm that under full workload, CPU core temperatures stay below the thermal throttling limit (typically 90-100°C for modern processors).</li><li><strong>CPU Package Power</strong>: Track power consumption (in Watts) to verify power plan configurations are correctly applying voltages.</li></ul></li></ul><hr><h2 id="🔍-the-before-after-optimization-verification-flow" tabindex="-1">🔍 The &quot;Before &amp; After&quot; Optimization Verification Flow <a class="header-anchor" href="#🔍-the-before-after-optimization-verification-flow" aria-label="Permalink to &quot;🔍 The &quot;Before &amp; After&quot; Optimization Verification Flow&quot;">​</a></h2><p>To confirm your optimizations are successful and safe, follow this baseline diagnostic routine:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[1. Baseline HWMonitor Run] ──&gt; [2. Apply Registry Tweaks] ──&gt; [3. Benchmark Run] ──&gt; [4. Verify Thermal Limits]</span></span></code></pre></div><h3 id="phase-1-establish-the-baseline" tabindex="-1">Phase 1: Establish the Baseline <a class="header-anchor" href="#phase-1-establish-the-baseline" aria-label="Permalink to &quot;Phase 1: Establish the Baseline&quot;">​</a></h3><ol><li>Before applying any tweaks, close all active windows.</li><li>Launch <code>HW-Monitor.exe</code> and let the computer sit idle for 5 minutes.</li><li>Note your <strong>Idle Temperatures</strong> for CPU and GPU (healthy ranges are typically 35-50°C).</li><li>Run a demanding game or benchmark (like Cinebench or Superposition) for 10 minutes.</li><li>Record your <strong>Maximum Temperatures</strong> and CPU boost clock stability.</li></ol><h3 id="phase-2-apply-system-optimizations" tabindex="-1">Phase 2: Apply System Optimizations <a class="header-anchor" href="#phase-2-apply-system-optimizations" aria-label="Permalink to &quot;Phase 2: Apply System Optimizations&quot;">​</a></h3><ol><li>Create a System Restore Point.</li><li>Run your preferred optimization scripts (e.g., MMCSS gaming priority, RAM compression off, CPU Power Plan).</li></ol><h3 id="phase-3-verify-the-changes" tabindex="-1">Phase 3: Verify the Changes <a class="header-anchor" href="#phase-3-verify-the-changes" aria-label="Permalink to &quot;Phase 3: Verify the Changes&quot;">​</a></h3><ol><li><strong>Verify Clock Speeds via CPU-Z / GPU-Z</strong>: <ul><li>Open <code>CPU-Z.exe</code>. Ensure the CPU remains at high boost frequencies and does not drop during workload transitions.</li><li>Open <code>GPU-Z.exe</code>. Check the sensors to confirm the graphics card is hitting its maximum clock limits.</li></ul></li><li><strong>Verify Temperatures and Throttling via HWMonitor</strong>: <ul><li>Re-run your benchmark tool with HWMonitor active in the background.</li><li>Review the <strong>Max Column</strong> in HWMonitor: <ul><li>Ensure motherboard VRMs, NVMe SSDs, and CPU cores stay well within safe limits.</li><li>If temperatures exceed safe limits (CPU &gt; 90°C or GPU &gt; 85°C), disable custom power plan optimizations or restore CPU mitigations in <code>InSpectre.exe</code> to reduce thermal pressure.</li></ul></li></ul></li></ol>',20)])])}const u=t(r,[["render",s]]);export{p as __pageData,u as default};
